function solve(nums) {
    const onesIndices = [];
    const twosIndices = [];

    // Find all indices where nums[i] is 1 or 2
    for (let i = 0; i < nums.length; i++) {
        if (nums[i] === 1) {
            onesIndices.push(i);
        } else if (nums[i] === 2) {
            twosIndices.push(i);
        }
    }

    // Check if any valid pair exists
    if (onesIndices.length === 0 || twosIndices.length === 0) {
        return -1;
    }

    let minDiff = Infinity;

    // Iterate through all pairs of indices (i, j) where nums[i]=1 and nums[j]=2
    for (const i of onesIndices) {
        for (const j of twosIndices) {
            const diff = Math.abs(i - j);
            if (diff < minDiff) {
                minDiff = diff;
            }
        }
    }

    return minDiff;
}

